// Extract job_id and status from Safe Command API envelope.
// The start route uses Popen and returns JSON directly (not wrapped in stdout).
// Do NOT log the X-Adwi-Secret header value.
const env = $input.item.json;

// The start route returns JSON directly from _handle_e2e_start
if (env.job_id) {
  return {
    ok: true,
    job_id: env.job_id,
    status: env.status || 'started',
    pid: env.pid || null,
    status_route: env.status_route || '/adwi-e2e-auto-loop-status'
  };
}

// Fallback: wrapped in stdout envelope
const raw = (env.stdout || '').trim();
if (!raw) return { ok: false, error: 'Empty response from /adwi-e2e-auto-loop-start' };
try {
  const result = JSON.parse(raw);
  return {
    ok: true,
    job_id: result.job_id || 'unknown',
    status: result.status || 'started',
    pid: result.pid || null
  };
} catch (e) {
  return { ok: false, error: String(e), raw: String(raw).slice(0, 200) };
}

// Extract status from Safe Command API envelope.
// Status route uses subprocess.run — stdout is wrapped in envelope.
const env = $input.item.json;
const raw = (env.stdout || '').trim();
if (!raw) return { ok: false, error: 'Empty stdout from /adwi-e2e-auto-loop-status' };
try {
  const s = JSON.parse(raw);
  return {
    ok: true,
    job_id: s.job_id || null,
    status: s.status || null,
    combined_pct: s.final_combined_pct || null,
    needs_llm_review: s.needs_llm_review || false,
    cycle: s.cycle || 0,
    max_cycles: s.max_cycles || 3,
    updated_at: s.updated_at || null,
    stop_reason: s.stop_reason || null
  };
} catch (e) {
  return { ok: false, error: String(e), raw: String(raw).slice(0, 200) };
}
